// ── Helpers ───────────────────────────────────────────────────────────────────

export function getSpellsForClass(className: string): SpellEntry[] {
  return SPELLS.filter(s => s.classes.includes(className));
}

export function getCantripsForClass(className: string): SpellEntry[] {
  return SPELLS.filter(s => s.level === 0 && s.classes.includes(className));
}

export function getSpellsByLevel(className: string, spellLevel: number): SpellEntry[] {
  return SPELLS.filter(s => s.level === spellLevel && s.classes.includes(className));
}
